const items = $input.all();
const alerts = [];

for (const item of items) {
  const quote = Array.isArray(item.json) ? item.json[0] : item.json;
  if (!quote?.symbol) continue;

  const price = quote.price || 0;
  const ticker = quote.symbol;
  const meta = typeof item.json.metadata === 'string' ? JSON.parse(item.json.metadata) : (item.json.metadata || {});
  const stop = parseFloat(meta.stop) || 0;
  const target = parseFloat(meta.target) || 0;

  if (stop > 0 && price <= stop) {
    alerts.push({json: {ticker, alert_type: 'stop_loss_hit', message: `STOP HIT: ${ticker} at $${price.toFixed(2)} (stop was $${stop.toFixed(2)}). EXIT POSITION.`, severity: 'critical', price, level: stop}});
  } else if (target > 0 && price >= target) {
    alerts.push({json: {ticker, alert_type: 'target_reached', message: `TARGET REACHED: ${ticker} at $${price.toFixed(2)} (target was $${target.toFixed(2)}). Consider taking profits.`, severity: 'warning', price, level: target}});
  } else if (stop > 0 && price < stop * 1.02) {
    alerts.push({json: {ticker, alert_type: 'approaching_stop', message: `WARNING: ${ticker} at $${price.toFixed(2)} approaching stop $${stop.toFixed(2)} (${((price/stop-1)*100).toFixed(1)}% away)`, severity: 'warning', price, level: stop}});
  }
}

return alerts.length > 0 ? alerts : [{json: {skip: true}}];
